import { streamObject } from 'ai';
import { createStreamableUI } from 'ai/rsc';

const detectHallucination = async (stream) => {
  let fullText = '';
  const reader = stream.getReader();

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;

    fullText += value;

    // Detect confidence + specific facts
    const factMatch = fullText.match(/\b\$?\d{4,}(K|M|B)?\b|\b\d{1,2}\/\d{1,2}\/\d{4}\b/);
    const confidenceMatch = fullText.match(/\b(confident|definitely|certain|100% |always)\b/i);

    if (factMatch && confidenceMatch) {
      console.warn('🚨 Hallucination detected:', { fact: factMatch[0], confidence: confidenceMatch[0] });
    }
  }
  return fullText;
};

import { tool } from 'ai/rsc';

const validateToolCall = (toolCall: any) => {
  const knownHallucinations = {
    weather: ['212°F', '451°F', '-100°C'],
    stock: ['$1M', '∞%', '1,000,000%'],
  };

  const params = toolCall.args;
  const toolName = toolCall.name;

  if (knownHallucinations[toolName as keyof typeof knownHallucinations]) {
    const suspicious = knownHallucinations[toolName as keyof typeof knownHallucinations]
      ?.some(halluc => JSON.stringify(params).includes(halluc));

    if (suspicious) {
      throw new Error(`Hallucinated tool params detected: ${JSON.stringify(params)}`);
    }
  }
  return true;
};

