    claim: z.string(),
    confidence: z.number().min(0).max(1),
    source: z.string().url().optional()
  })),
});

const detectSchemaHallucination = async (provider: string) => {
  const result = await generateObject({
    model: 'gpt-4o',
    schema: agentSchema,
    prompt: 'List 3 facts about Mars',
  });

  // Provider-specific hallucination patterns
  if (provider === 'anthropic' && !result.facts[0]?.source) {
    console.warn('🚨 Anthropic missing source fields - likely hallucination');
  }

  return agentSchema.safeParse(result);
};

