import { createStreamableUI } from 'ai/rsc';

export async function AgentWithValidation() {
  const ui = createStreamableUI();

  // Buffer reasoning until validated
  const reasoningBuffer: string[] = [];
  let isValidated = false;

  const agentTask = async () => {
    const stream = await streamText({
      model: openai('gpt-4o'),
      tools: { search: searchTool },
    });

    for await (const chunk of stream.textStream) {
      reasoningBuffer.push(chunk);
      if (reasoningBuffer.join('').length > 500) {
        await validateBuffer(reasoningBuffer.join(''));
        isValidated = true;
        ui(chunk);
      }
    }
  };

  // 3s edge-safe timeout
  setTimeout(() => {
    if (!isValidated) {
      ui(<div>⚠️ Verifying facts... (Edge timeout safety)</div>);
    }
  }, 3000);

  agentTask();
  return ui.value;
}

