import { generateText, StreamData } from 'ai';

export async function streamWithFactCheck(prompt: string) {
  const facts: string[] = [];

  const { textStream } = await generateText({
    model: openai('gpt-4o'),
    prompt,
    onFinish: async ({ text }) => {
      // Extract facts post-generation
      const factRegex = /\b(?:in \d{4}|\$\d+(?:K|M|B)?|at \d+°(?:F|C))\b/gi;
      facts.push(...text.match(factRegex) || []);

      // Parallel validation
      await Promise.all(facts.map(fact => validateFact(fact)));
    },
  });

  return {
    stream: textStream.pipeThrough(new TransformStream({
      transform(chunk, controller) {
        // Annotate stream with validation status
        controller.enqueue(`[✓ Validated] ${chunk}`);
      }
    })),
    facts
  };
}

